var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":null,"text":{"KOREA":"최후의 수단이라 생각한 마지막 카드마저 꺼냈음에도 쓰러지지 않는 금발의 전사.","JPN":"最後の手段であるはずの切り札まで出したのに倒すことができない金髪の戦士。","ENG":"The Blonde Warrior didn't fall even after using what was thought to be a last resort.","TWN":"掏出最後的王牌也打不倒的金髮戰士。"},"stage":{"bg":"BLACK","bgm":"BATTLE_BOSS_04_HOLY","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}},"voice":"AB_UI_UNIT_VOICE_NKM_UNIT_ACADEMY_CA_TWINTAIL_IN_TRAILER_5"},{"id":"L3_1","type":"dialog","speaker":null,"text":{"KOREA":"세상의 정점에 올라 왕좌에 앉는 순간까지 단 한 걸음이었다.","JPN":"世界の頂点に上り詰め王座につく瞬間まであと一歩だった。","ENG":"There was only one step left to reach the pinnacle of the world and claim the throne.","TWN":"距離登上世界之巔的寶座，只剩一步之遙。"},"stage":{"bg":"BLACK","bgm":"BATTLE_BOSS_04_HOLY","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}},"voice":"AB_UI_UNIT_VOICE_NKM_UNIT_ACADEMY_CA_TWINTAIL_IN_TRAILER_6"},{"id":"L4_1","type":"dialog","speaker":null,"text":{"KOREA":"어째서……. 단 한걸음, 고작 단 한걸음만이 남았을 터였다…….","JPN":"どうして……あと一歩、たった一歩足りないだけだった……。","ENG":"But why...? It was in arm's reach, and all it would take was just one more step forward...","TWN":"為什麼……就差一步，就那麼一步……"},"stage":{"bg":"BLACK","bgm":"BATTLE_BOSS_04_HOLY","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}},"voice":"AB_UI_UNIT_VOICE_NKM_UNIT_ACADEMY_CA_TWINTAIL_IN_TRAILER_7"},{"id":"L9_1","type":"dialog","speaker":null,"text":{"KOREA":"이건 내가 만들어 놓은 세상이야! 그 누구도 내 법칙에 거스를 순 없었어!","JPN":"これは私が作った世界よ！　誰も私の法則に逆らうことはできなかった！","ENG":"I created this world! No one's been able to defy my laws!","TWN":"這是我所創造的世界！沒有人可以違背我的法則！"},"stage":{"bg":"COUNTERSIDE_RED_ADF","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}},"voice":"AB_UI_UNIT_VOICE_NKM_UNIT_ACADEMY_CA_TWINTAIL_IN_TRAILER_8"},{"id":"L10_1","type":"dialog","speaker":null,"text":{"KOREA":"내가 만들어 놓은 세계의 법칙이! 한낱 인간이 바꿀 수 있을 만큼 그렇게 만만해 보여?","JPN":"私が作った世界の法則は！　一介の人間に変えられるほど、そんなに単純なものに見える？","ENG":"Do you think this world's laws that I created are simple enough that a mere human can change them?","TWN":"我所創造的世界法則！難道那麼輕易就能夠被區區的人類改變嗎？"},"stage":{"bg":"COUNTERSIDE_RED_ADF","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}},"voice":"AB_UI_UNIT_VOICE_NKM_UNIT_ACADEMY_CA_TWINTAIL_IN_TRAILER_9"},{"id":"L11_1","type":"dialog","speaker":null,"text":{"KOREA":"어, 어떻게…! 너한텐 정말 그게 가능하다는 거야…?!","JPN":"ど、どうして……！　あんたには本当にそれが可能だっていうの……？","ENG":"B-but how...?! How is that even possible...?!","TWN":"怎麼會…！對你來說真的是有可能的嗎…？！"},"stage":{"bg":"COUNTERSIDE_RED_ADF","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}},"voice":"AB_UI_UNIT_VOICE_NKM_UNIT_ACADEMY_CA_TWINTAIL_IN_TRAILER_10"},{"id":"L12_1","type":"dialog","speaker":null,"text":{"KOREA":"대답해! 너는… 정말 그렇단 말이야?! 애송이, 아니, 나이엘 블루스틸이여!","JPN":"答えて！　あんたは……本当にそうなの！？　小娘、いいえ、ナイエル・ブルースチールよ！","ENG":"Answer me! Can you... really do that?! Kid, no, Naielle Bluesteel!!","TWN":"回答我！你…真的有那麼厲害嗎？！小子，說錯。回答我，奈爾·布魯斯提爾！"},"stage":{"bg":"COUNTERSIDE_RED_ADF","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}},"voice":"AB_UI_UNIT_VOICE_NKM_UNIT_ACADEMY_CA_TWINTAIL_IN_TRAILER_11"},{"id":"L15_1","type":"dialog","speaker":"TWINTAIL_ACADEMY_NULL_NULL","text":{"KOREA":"어때? 이건 내가 최강의 기사와 펼쳤던 전투를 담은 책이야.\xA0","JPN":"どう？　これは私が戦った最強の騎士との戦闘について記した本よ。","ENG":"What do you think? This is a book that describes my battle against the strongest knight.","TWN":"怎麼樣？這本書裡面寫到的，就是是我跟最強騎士決鬥的故事。"},"stage":{"bg":"DORMITORY_2","bgm":"THEMA_CHILD","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"TWINTAIL_ACADEMY_NULL_NULL","face":"UNIT_LAUGH"},"R":null}},"sfx":"FX_CUTSCEN_TADA2"},{"id":"L16_1","type":"dialog","speaker":"TWINTAIL_ACADEMY_NULL_NULL","text":{"KOREA":"이날 내가 아니었다면, 세계는 진짜 끝장났을지도 모른다고?","JPN":"私が戦ってなかったら、世界は本当に終わっていたかもしれないのよ？","ENG":"If it weren't for me, the world might've really ended.","TWN":"那天要不是有我，說不定就世界末日咧？"},"stage":{"bg":"DORMITORY_2","bgm":"THEMA_CHILD","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"TWINTAIL_ACADEMY_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"CHILDREN_BARCODE_TWO_NULL","text":{"KOREA":"우와……!","JPN":"わあ……！","ENG":"Whoa...!","TWN":"哇喔……！"},"stage":{"bg":"DORMITORY_2","bgm":"THEMA_CHILD","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CHILDREN_BARCODE_ONE_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"CHILDREN_BARCODE_TWO_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L21_1","type":"dialog","speaker":"CHILDREN_BARCODE_ONE_NULL","text":{"KOREA":"그럼 언니가 세상에서 제일 강한 거예요?","JPN":"じゃあ、お姉ちゃんは世界一強いの？","ENG":"Then, you're the strongest in the world now?","TWN":"那姊姊不就是世界上最強的人嗎？"},"stage":{"bg":"DORMITORY_2","bgm":"THEMA_CHILD","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CHILDREN_BARCODE_ONE_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"CHILDREN_BARCODE_TWO_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L23_1","type":"dialog","speaker":"TWINTAIL_ACADEMY_NULL_NULL","text":{"KOREA":"그럼~ 너희들도 나중에 크면 나이엘 선배의 위대함을 잘 기억해 두도록 해.","JPN":"もちろん！　あんたたちも、このナイエル先輩の偉大さをよーく覚えておくことね。","ENG":"Of course! So make sure to never forget the greatness of Naielle Bluesteel when you grow up.","TWN":"那當然～所以你們長大後也不可以忘記奈爾姊姊有多偉大喔。"},"stage":{"bg":"DORMITORY_2","bgm":"THEMA_CHILD","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"TWINTAIL_ACADEMY_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"TWINTAIL_ACADEMY_NULL_NULL","text":{"KOREA":"훗, 모처럼 연기까지 연습한 보람이 있어. 애들은 참 순진해서 좋다니까.","JPN":"ふっ、演技の練習までしておいた甲斐があった。子どもたちは単純でいいわ。","ENG":"Heh, I guess it was worth practicing my acting. I love how naive kids are.","TWN":"嘿嘿，辛苦練演技總算沒白費，小朋友們還真天真。"},"stage":{"bg":"DORMITORY_2","bgm":"THEMA_CHILD","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"TWINTAIL_ACADEMY_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L28_1","type":"dialog","speaker":"LUCID_BARCODE_NULL_NULL","text":{"KOREA":"재밌었니? 나이엘 언니가 어제 힘들게 쓰신 거야.","JPN":"面白かった？　ナイエルお姉ちゃんが昨日頑張って書いたお話だよ。","ENG":"Was it fun? Naielle worked hard to write it yesterday.","TWN":"喜歡嗎？這是奈爾姊姊昨天辛苦完成的故事喔。"},"stage":{"bg":"DORMITORY_2","bgm":"THEMA_CHILD","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LUCID_BARCODE_NULL_NULL","face":"UNIT_LAUGH"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L30_1","type":"dialog","speaker":"TWINTAIL_ACADEMY_NULL_NULL","text":{"KOREA":"이, 이건 실화를 기반으로 만든 거라고!","JPN":"こ、これは実話に基づいて書いたんだから！","ENG":"Hey! This is based on a true story!","TWN":"這，這是根據真人真事改編的故事！"},"stage":{"bg":"DORMITORY_2","bgm":"THEMA_CHILD","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"TWINTAIL_ACADEMY_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L32_1","type":"dialog","speaker":"LUCID_BARCODE_NULL_NULL","text":{"KOREA":"아하하, 그랬었죠. 정말 고생 많으셨어요.","JPN":"あはは、そうでしたね。お疲れさまでした。","ENG":"Ah hah hah, that's right. Great work, Naielle.","TWN":"哈哈哈，是啊。真的辛苦你了。"},"stage":{"bg":"DORMITORY_2","bgm":"THEMA_CHILD","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LUCID_BARCODE_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L35_1","type":"dialog","speaker":"CHILDREN_BARCODE_ONE_NULL","text":{"KOREA":"언니가 세상에서 제일 강한 카운터래요!","JPN":"お姉ちゃんは世界一強いカウンターだって！","ENG":"She said she's the strongest Counter in the world!","TWN":"姊姊是世界上最強的制裁者！"},"stage":{"bg":"DORMITORY_2","bgm":"THEMA_CHILD","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CHILDREN_BARCODE_ONE_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"CHILDREN_BARCODE_TWO_NULL","face":"UNIT_LAUGH"}}}},{"id":"L36_1","type":"dialog","speaker":"CHILDREN_BARCODE_TWO_NULL","text":{"KOREA":"전설의 기사랑 싸워서 한방에 이겼대요!","JPN":"伝説の騎士と戦って、一撃で倒したんだよ！","ENG":"She fought against the legendary knight and beat him in one blow!","TWN":"聽說她和傳說中的騎士戰鬥，一招就贏了！"},"stage":{"bg":"DORMITORY_2","bgm":"THEMA_CHILD","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CHILDREN_BARCODE_ONE_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"CHILDREN_BARCODE_TWO_NULL","face":"UNIT_LAUGH"}}}},{"id":"L38_1","type":"dialog","speaker":"LUCID_BARCODE_NULL_NULL","text":{"KOREA":"아하하, 나이엘 학생은 정말 대단하네요.","JPN":"あはは、ナイエルさんは本当にすごいですね。","ENG":"Ah hah hah. You're amazing, Naielle.","TWN":"哈哈哈，奈爾同學真是厲害啊。"},"stage":{"bg":"DORMITORY_2","bgm":"THEMA_CHILD","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LUCID_BARCODE_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L39_1","type":"dialog","speaker":"LUCID_BARCODE_NULL_NULL","text":{"KOREA":"지난겨울 때부터 항상 봉사하러 와 주시고, 정말 든든했답니다.","JPN":"去年の冬から何回もボランティアに来てくださって、心強かったです。","ENG":"You've been coming here to volunteer since last winter, and you've been so helpful.","TWN":"從去年冬天開始你就一直來幫忙，真的很可靠呢。"},"stage":{"bg":"DORMITORY_2","bgm":"THEMA_CHILD","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LUCID_BARCODE_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L40_1","type":"dialog","speaker":"LUCID_BARCODE_NULL_NULL","text":{"KOREA":"혹시…… 오늘이 마지막 날이었죠? 아이들이 많이 슬퍼하겠어요.","JPN":"確か……今日が最後の日ですね。子どもたちが寂しがるでしょう。","ENG":"Today... is your last day, right? The children will be so sad.","TWN":"難道……今天是最後一天嗎？孩子們會很難過的。"},"stage":{"bg":"DORMITORY_2","bgm":"THEMA_CHILD","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LUCID_BARCODE_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L42_1","type":"dialog","speaker":"TWINTAIL_ACADEMY_NULL_NULL","text":{"KOREA":"어쩔 수 없잖아? 아무리 나라도 평생 봉사만 할 수는 없다고.","JPN":"仕方ないでしょ？　いくら私でも、一生ボランティアはできないもの。","ENG":"It had to end someday. I can't continue volunteering for the rest of my life.","TWN":"沒辦法啊？再怎麼說我也不能一輩子只做志工吧。"},"stage":{"bg":"DORMITORY_2","bgm":"THEMA_CHILD","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"TWINTAIL_ACADEMY_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L43_1","type":"dialog","speaker":"TWINTAIL_ACADEMY_NULL_NULL","text":{"KOREA":"뭐, 가끔 정도라면 찾아와 줄 수 있긴 하지만.","JPN":"ま、たまになら来てあげてもいいわよ。","ENG":"Well, I guess I could come visit every once in a while.","TWN":"嗯，偶爾來看看還是可以的。"},"stage":{"bg":"DORMITORY_2","bgm":"THEMA_CHILD","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"TWINTAIL_ACADEMY_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L46_1","type":"dialog","speaker":"CHILDREN_BARCODE_ONE_NULL","text":{"KOREA":"에엥?! 언니 이제 안 와요?","JPN":"ええっ！？　お姉ちゃん、もう来ないの？","ENG":"Huh?! You're not coming anymore?","TWN":"啊？！姊姊以後不來了？"},"stage":{"bg":"DORMITORY_2","bgm":"THEMA_CHILD","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CHILDREN_BARCODE_ONE_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"CHILDREN_BARCODE_TWO_NULL","face":"UNIT_HATE"}}}},{"id":"L47_1","type":"dialog","speaker":"CHILDREN_BARCODE_TWO_NULL","text":{"KOREA":"가지 마! 언니 없으면 심심하단 말이야!","JPN":"ダメだよ！　お姉ちゃんがいないと退屈なの！","ENG":"Don't leave! It's no fun without you!","TWN":"不要走！沒有姊姊我會很無聊的！"},"stage":{"bg":"DORMITORY_2","bgm":"THEMA_CHILD","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CHILDREN_BARCODE_ONE_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"CHILDREN_BARCODE_TWO_NULL","face":"UNIT_HATE"}}}},{"id":"L49_1","type":"dialog","speaker":"TWINTAIL_ACADEMY_NULL_NULL","text":{"KOREA":"자, 잠깐! 달려들지 마! 그만!","JPN":"ちょ、ちょっと離れなさい！　やめなさいって！","ENG":"H-hey! Get off me! Stop it!","TWN":"等，等等！不要衝過來！停下！"},"stage":{"bg":"DORMITORY_2","bgm":"THEMA_CHILD","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"TWINTAIL_ACADEMY_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}},"sfx":"FX_CUTSCEN_BOW"},{"id":"L50_1","type":"dialog","speaker":"TWINTAIL_ACADEMY_NULL_NULL","text":{"KOREA":"가끔 정도는 찾아올 테니까 울지 좀 마. 그런 건 하나도 멋지지 않다고!","JPN":"たまには来てあげるから泣くんじゃないの。そんな姿、全然格好よくないわよ！","ENG":"I'll visit once in a while, so stop crying. Crying is not cool!","TWN":"偶爾會回來看你們的，別哭啦。這樣可一點都不酷了！"},"stage":{"bg":"DORMITORY_2","bgm":"THEMA_CHILD","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"TWINTAIL_ACADEMY_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L1_1","type":"dialog","speaker":"TWINTAIL_ACADEMY_NULL_NULL","text":{"KOREA":"너희들, 나중에 나처럼 강한 카운터가 되고 싶다고 했지?","JPN":"あんたたち、将来は私みたいに強いカウンターになりたいんでしょ？","ENG":"You all said that you wanted to become a strong Counter like me one day, right?","TWN":"你們不是說過以後想成為像我一樣強大的制裁者嗎？"},"stage":{"bg":"DORMITORY_2","bgm":"THEMA_CHILD","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"TWINTAIL_ACADEMY_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L2_1","type":"dialog","speaker":"TWINTAIL_ACADEMY_NULL_NULL","text":{"KOREA":"그렇게 되려면 멋지게 헤어지는 법부터 알아야…….","JPN":"それなら、まずは別れる時も格好よく……","ENG":"Then, you need to learn how to say goodbye–","TWN":"要做到那樣，首先得學會如何瀟灑的離別……"},"stage":{"bg":"DORMITORY_2","bgm":"THEMA_CHILD","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"TWINTAIL_ACADEMY_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"CHILDREN_BARCODE_NULL_NULL","text":{"KOREA":"싫어!","JPN":"やだ！","ENG":"NO!","TWN":"不要！"},"stage":{"bg":"DORMITORY_2","bgm":"THEMA_CHILD","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHILDREN_BARCODE_NULL_NULL","face":"UNIT_HATE"},"R":null}},"sfx":"FX_CUTSCEN_WIND2"},{"id":"L6_1","type":"dialog","speaker":"TWINTAIL_ACADEMY_NULL_NULL","text":{"KOREA":"으아악~ 어딜 붙잡는 거야!","JPN":"わああっ！　どこ掴んでるのよ！","ENG":"Gaah! Will you stop grabbing me?!","TWN":"啊啊啊～你抓哪裡呢！"},"stage":{"bg":"DORMITORY_2","bgm":"THEMA_CHILD","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"TWINTAIL_ACADEMY_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_04"},{"id":"L9_1","type":"dialog","speaker":"TWINTAIL_ACADEMY_NULL_NULL","text":{"KOREA":"어휴……. 쬐끄만 녀석들이 하루 종일 얼마나 들러붙던지….","JPN":"まったく……あのちびっこたちに一日中くっつかれて……","ENG":"Ugh... Those kids wouldn't let me be for even a second...","TWN":"唉……這些小傢伙們整天都粘著我……"},"stage":{"bg":"ROOM_02","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"TWINTAIL_ACADEMY_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}},"sfx":"FX_CUTSCEN_DOOR_WOOD"},{"id":"L11_1","type":"dialog","speaker":"PRESIDENT_SCHOOL_NULL_NULL","text":{"KOREA":"지금까지 고생 많았어요. 선생님께서 많이 아쉬워 하시더군요.","JPN":"ご苦労さまでした。先生がとても残念がっていましたよ。","ENG":"You did good. Miss Lucid said that she'll miss you.","TWN":"這段時間你辛苦了，老師很捨不得你呢。"},"stage":{"bg":"ROOM_02","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PRESIDENT_SCHOOL_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"PRESIDENT_SCHOOL_NULL_NULL","text":{"KOREA":"후훗, 나이엘은 아이들 돌보는 일에 소질이 있는 것 같아요.","JPN":"ふふっ、ナイエルさんは子どもの面倒を見る才能があるみたいです。","ENG":"Hah hah, I believe you are a natural when it comes to taking care of children.","TWN":"呵呵，看來奈爾很擅長照顧孩子呢。"},"stage":{"bg":"ROOM_02","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PRESIDENT_SCHOOL_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"PRESIDENT_SCHOOL_NULL_NULL","text":{"KOREA":"여러 보육원에서 나이엘을 찾는 전화가 자주 올 정도였거든요.","JPN":"いくつかの養護施設から、ナイエルさんに来てほしいという電話がかかってきたんですよ。","ENG":"Enough so that various orphanages frequently call asking for you.","TWN":"經常有多家育幼院打電話來找奈爾。"},"stage":{"bg":"ROOM_02","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PRESIDENT_SCHOOL_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"PENCIL_SCHOOL_NPC_NULL","text":{"KOREA":"와~ 정말요?","JPN":"わあ～本当ですか？","ENG":"Whoa! Really?","TWN":"哇～真的嗎？"},"stage":{"bg":"ROOM_02","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"PENCIL_SCHOOL_NPC_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"CIEL_ACADEMY_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L17_1","type":"dialog","speaker":"CIEL_ACADEMY_NULL_NULL","text":{"KOREA":"이사장님께서 봉사 활동을 시킨 것은 정말 좋은 판단이었던 것 같소.","JPN":"彼女にボランティア活動をさせた理事長の判断は、間違っていませんでしたね。","ENG":"It seems that Ms. Chairwoman made the right decision to have her do volunteer work.","TWN":"理事長讓我們參加志工活動，真是一個明智的決定。"},"stage":{"bg":"ROOM_02","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"PENCIL_SCHOOL_NPC_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"CIEL_ACADEMY_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L18_1","type":"dialog","speaker":"CIEL_ACADEMY_NULL_NULL","text":{"KOREA":"하지만 오늘부로 기간이 끝났으니 아이들이 섭섭했겠구려.","JPN":"しかしそれも本日で終わり……子どもたちも寂しがるでしょう。","ENG":"But since it has come to an end as of today, the children must be disappointed.","TWN":"但是今天期限已到，孩子們一定很失望吧。"},"stage":{"bg":"ROOM_02","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"PENCIL_SCHOOL_NPC_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"CIEL_ACADEMY_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L20_1","type":"dialog","speaker":"TWINTAIL_ACADEMY_NULL_NULL","text":{"KOREA":"햐~ 드디어 해방이라는 거지!","JPN":"はあ～やっと解放されたってことよね！","ENG":"Ahh! It means I'm finally free!","TWN":"哈～終於解放了！"},"stage":{"bg":"ROOM_02","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"TWINTAIL_ACADEMY_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"TWINTAIL_ACADEMY_NULL_NULL","text":{"KOREA":"뭐…. 애들이라면 가끔 놀아줄 생각이긴 하지만….","JPN":"ま、子どもたちのことは嫌いじゃないし、たまには遊んでやるつもりだけど。","ENG":"But... I still do plan on visiting them from time to time…","TWN":"嗯……偶爾還是想陪這些孩子們玩一玩的……"},"stage":{"bg":"ROOM_02","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"TWINTAIL_ACADEMY_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"PENCIL_SCHOOL_NPC_NULL","text":{"KOREA":"시키지 않아도 봉사하겠다니…….","JPN":"強制じゃなくてもボランティアをするつもりだなんて……","ENG":"Volunteering without someone telling you to...?","TWN":"即使沒吩咐你做，你也想主動幫忙……"},"stage":{"bg":"ROOM_02","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PENCIL_SCHOOL_NPC_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"PENCIL_SCHOOL_NPC_NULL","text":{"KOREA":"너…… 진짜 나이엘 맞아?!","JPN":"あなた……本当にナイエルなの！？","ENG":"Are you... really the Naielle I knew?!","TWN":"你……真的是奈爾嗎？！"},"stage":{"bg":"ROOM_02","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PENCIL_SCHOOL_NPC_NULL","face":"UNIT_SURPRISE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L26_1","type":"dialog","speaker":"TWINTAIL_ACADEMY_NULL_NULL","text":{"KOREA":"그, 그냥 내 평판이 좋아져야 취업할 때 편하니까 하는 거야!","JPN":"そ、それは！　私の評判がよくなったら就職にも役立つからよ！","ENG":"I-I'm only doing it because it'll be easier for me to get a job if my reputation improves!","TWN":"那，那是因為大家對我的評價好的話，找工作時會更方便而已！"},"stage":{"bg":"ROOM_02","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"TWINTAIL_ACADEMY_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L27_1","type":"dialog","speaker":"TWINTAIL_ACADEMY_NULL_NULL","text":{"KOREA":"별것도 아닌 걸로 호들갑 떨긴…….","JPN":"そんなに驚くことじゃないでしょ……","ENG":"So, there's nothing to overreact...","TWN":"這又沒什麼……"},"stage":{"bg":"ROOM_02","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"TWINTAIL_ACADEMY_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L28_1","type":"dialog","speaker":"TWINTAIL_ACADEMY_NULL_NULL","text":{"KOREA":"후~ 그럼 해방된 기념으로 뭘 해볼까나?","JPN":"ふう～ボランティアから解放された記念に、何からしようかな？","ENG":"Whew... Now, what should I do to commemorate this newfound freedom?","TWN":"呼～那麼作為解放的紀念，要做點什麼呢？"},"stage":{"bg":"ROOM_02","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"TWINTAIL_ACADEMY_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L30_1","type":"dialog","speaker":"TWINTAIL_ACADEMY_NULL_NULL","text":{"KOREA":"그러고 보니 그 루시드라는 선생……. 내 이야길 소설로만 치부했었지?","JPN":"そういえば、あのルシードとかいう教師……私の話を作り話扱いしたのよね。","ENG":"Come to think of it, that teacher, Lucid... just treated my story like a novel, didn't she?","TWN":"這麼說來，那位叫露西德的老師……是不是把我的故事當成小說在看？"},"stage":{"bg":"ROOM_02","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"TWINTAIL_ACADEMY_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L32_1","type":"dialog","speaker":"TWINTAIL_ACADEMY_NULL_NULL","text":{"KOREA":"지금이라도 모의전투 순위를 갈아치워서 확실히 증명해 주겠어!","JPN":"今からでも模擬戦闘の順位を更新して、確実に証明してやる！","ENG":"I'll prove to her that I'm the real deal by climbing back to the top of the simulation training!","TWN":"現在我就打破模擬戰鬥的排名證明給你看！"},"stage":{"bg":"ROOM_02","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"TWINTAIL_ACADEMY_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}},"sfx":"FX_CUTSCEN_TADA2"},{"id":"L35_1","type":"dialog","speaker":"AI_SCHOOL_NULL_NULL","text":{"KOREA":"시뮬레이션에 입장합니다. 참여하실 분은 자리에 대기하여 주십시오.","JPN":"シミュレーションに入場します。参加を希望する方は、その場で待機してください。","ENG":"Entering simulation. Participants are asked to wait in their seats.","TWN":"進入模擬。請參與者在座位上等待。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L36_1","type":"dialog","speaker":"AI_SCHOOL_NULL_NULL","text":{"KOREA":"환영합니다. 나이엘 블루스틸 님.","JPN":"ようこそ、ナイエル・ブルースチール様。","ENG":"Welcome, Miss Naielle Bluesteel.","TWN":"歡迎你，奈爾·布魯斯提爾。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L37_1","type":"dialog","speaker":"AI_SCHOOL_NULL_NULL","text":{"KOREA":"타입 명. <color=#ffd34c>카운터즈 레거시</color>.","JPN":"タイプ名。<color=#ffd34c>カウンターズ・レガシー</color>。","ENG":"Type name. <color=#ffd34c>Counters Legacy</color>.","TWN":"類型名稱，<color=#ffd34c>制裁者的遺產</color>。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L38_1","type":"dialog","speaker":"TWINTAIL_ACADEMY_NULL_NULL","text":{"KOREA":"카운터즈 레거시……? 뭐야 그게?","JPN":"カウンターズ・レガシー……？　何それ？","ENG":"Counters Legacy...? What's that?","TWN":"制裁者的遺產……？那是什麼？"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L39_1","type":"dialog","speaker":"AI_SCHOOL_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L40_1","type":"dialog","speaker":"AI_SCHOOL_NULL_NULL","text":{"KOREA":"시스템 관리자 권한으로 접속 거부. 보안 프로토콜을 실행합니다.","JPN":"システム管理者の権限でアクセスが拒否されました。保安プロトコルを実行します。","ENG":"Access was denied by the system administrator. Initiating security protocols.","TWN":"以系統管理員許可權拒絕訪問。執行安全協議。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L42_1","type":"dialog","speaker":"AI_SCHOOL_NULL_NULL","text":{"KOREA":"모의전투 시뮬레이터는 현재 점검 중입니다.","JPN":"模擬戦闘シミュレーターは現在メンテナンス中です。","ENG":"The simulation training is currently under maintenance.","TWN":"模擬戰鬥模擬器目前正在檢查中。"},"stage":{"bg":"CORRIDOR","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L43_1","type":"dialog","speaker":"AI_SCHOOL_NULL_NULL","text":{"KOREA":"점검 종료 예정일 <color=#ffd34c>-미정-</color>","JPN":"メンテナンス終了予定日：<color=#ffd34c>未定</color>","ENG":"Scheduled maintenance end date, <color=#ffd34c>-Undetermined-</color>.","TWN":"維護結束日期<color=#ffd34c>-未定-</color>"},"stage":{"bg":"CORRIDOR","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L44_1","type":"dialog","speaker":"TWINTAIL_ACADEMY_NULL_NULL","text":{"KOREA":"엥, 뭐야?! 왜 갑자기 점검을 하는 건데?!","JPN":"ええ？　何！？　なんで急にメンテなの！？","ENG":"Huh? WHAT?! Why is it suddenly under maintenance?!","TWN":"咦，怎麼回事？！為什麼突然要維護？"},"stage":{"bg":"CORRIDOR","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"TWINTAIL_ACADEMY_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L46_1","type":"dialog","speaker":"CHAIR_SCHOOL_NULL_NULL","text":{"KOREA":"하암~ 꼭 있다니까……. 공지도 안 보고 난리 치는 녀석이…….","JPN":"ふああ～いるんだよねぇ……お知らせも確認しないで騒ぐやつ……","ENG":"*Yawn* There are always people like you... People who don't read the notice and make a fuss...","TWN":"哈啊～我就說有吧……不看公告就瞎嚷嚷的傢伙……"},"stage":{"bg":"CORRIDOR","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHAIR_SCHOOL_NULL_NULL","face":"UNIT_HATE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L47_1","type":"dialog","speaker":"CHAIR_SCHOOL_NULL_NULL","text":{"KOREA":"난 지금 무려 4시간이나 깨어 있어서 엄청 예민하다고…….","JPN":"私は今4時間も起きてて、すごく気が立ってるの。","ENG":"I've been up for four hours, so I'm really cranky...","TWN":"我現在已經醒了整整4個小時，非常敏感……"},"stage":{"bg":"CORRIDOR","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHAIR_SCHOOL_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L49_1","type":"dialog","speaker":"TWINTAIL_ACADEMY_NULL_NULL","text":{"KOREA":"고작 4시간 가지고 무슨…….","JPN":"たった4時間起きてるだけなのに何言って……","ENG":"It's just four hours...","TWN":"才4個小時……"},"stage":{"bg":"CORRIDOR","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"TWINTAIL_ACADEMY_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L50_1","type":"dialog","speaker":"TWINTAIL_ACADEMY_NULL_NULL","text":{"KOREA":"갑자기 무슨 점검인데? 고장이라도 났어?","JPN":"急に何のメンテするのよ？　どこか壊れたの？","ENG":"What's with the maintenance? Is it broken?","TWN":"突然要檢查什麼？是故障了嗎？"},"stage":{"bg":"CORRIDOR","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"TWINTAIL_ACADEMY_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L2_1","type":"dialog","speaker":"CHAIR_SCHOOL_NULL_NULL","text":{"KOREA":"이사장님은 지금 아카데미의 모의전투 시스템을 전면 개편할 계획이셔.","JPN":"理事長はアカデミーの模擬戦闘システムを全面的に改変するつもりだよ。","ENG":"The Chairwoman is planning a complete overhaul of the Academy's simulation training system.","TWN":"理事長現在計畫全面改版學院的模擬戰鬥系統。"},"stage":{"bg":"CORRIDOR","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHAIR_SCHOOL_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L3_1","type":"dialog","speaker":"CHAIR_SCHOOL_NULL_NULL","text":{"KOREA":"곧 새로운 시스템이 도입될 테니까 너도 대비해 두는 게 좋을걸?","JPN":"近いうちに新しいシステムが導入されるから、君も備えたほうがいいかもしれないよ。","ENG":"A new system will be implemented soon, so you better be prepared.","TWN":"很快就會引入新的系統，你最好也做好準備。"},"stage":{"bg":"CORRIDOR","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHAIR_SCHOOL_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"TWINTAIL_ACADEMY_NULL_NULL","text":{"KOREA":"웃겨! 고작 그런 것 때문에 하루 종일 점검을 하겠다고?","JPN":"ありえない！　それぐらいのことで一日中メンテですって？","ENG":"Pfft! It's going through maintenance all day just because of that?","TWN":"搞笑！就因為那種事要檢查一整天？"},"stage":{"bg":"CORRIDOR","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"TWINTAIL_ACADEMY_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"TWINTAIL_ACADEMY_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"CORRIDOR","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"TWINTAIL_ACADEMY_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"TWINTAIL_ACADEMY_NULL_NULL","text":{"KOREA":"잠깐, 방금 뭐라고 했어?\xA0","JPN":"ちょっと、あんた今なんて言った？\xA0","ENG":"Wait. What did you just say?\xA0","TWN":"等一下，你剛剛說什麼？"},"stage":{"bg":"CORRIDOR","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"TWINTAIL_ACADEMY_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"TWINTAIL_ACADEMY_NULL_NULL","text":{"KOREA":"새로운 시스템이 도입된다고?!","JPN":"新しいシステムが導入されるの！？","ENG":"A new system is being implemented?!","TWN":"要引入新系統了？！"},"stage":{"bg":"CORRIDOR","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"TWINTAIL_ACADEMY_NULL_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_CUTSCEN_TADA2"}]`);export{e as default};